import{_ as o,o as t,c as a,a8 as r}from"./chunks/framework.DvHWw5tv.js";const m=JSON.parse('{"title":"useColorComputed","description":"","frontmatter":{},"headers":[],"relativePath":"en/design/hooks/useColor.md","filePath":"en/design/hooks/useColor.md"}'),i={name:"en/design/hooks/useColor.md"};function s(n,e,l,d,c,p){return t(),a("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1776410922000"},[...e[0]||(e[0]=[r('<h1 id="usecolorcomputed" tabindex="-1">useColorComputed <a class="header-anchor" href="#usecolorcomputed" aria-label="Permalink to “useColorComputed”">​</a></h1><h2 id="usecolorcomputed-color-and-state-style-computation-hook" tabindex="-1">useColorComputed: Color and State Style Computation Hook <a class="header-anchor" href="#usecolorcomputed-color-and-state-style-computation-hook" aria-label="Permalink to “useColorComputed: Color and State Style Computation Hook”">​</a></h2><h2 id="pain-points" tabindex="-1">Pain Points <a class="header-anchor" href="#pain-points" aria-label="Permalink to “Pain Points”">​</a></h2><p>In UI components (e.g., Button, Tag, Badge), handling colors and interaction state styles is often one of the most complex and repetitive logic sets:</p><ul><li>Need to support custom <code>colorBg</code>, <code>colorText</code>, <code>colorBorder</code></li><li>In <code>plain</code> (plain) mode, background, text, and border colors must use theme variables based on type (e.g., primary, success) and handle transparency</li><li>Different interaction states (hover, active) require dynamic color switching</li><li>Disabled state requires uniform transparent background with fixed text/border colors</li><li>Colors may be CSS variables (e.g., <code>var(--el-color-primary)</code>) and require transparency conversion (e.g., <code>rgba(var(...), 0.2)</code>)</li></ul><p>Implementing these rules independently in each component leads not only to redundant logic but also to visual inconsistency, theme switching failures, and difficult dark mode adaptation.</p><h2 id="design-goals" tabindex="-1">Design Goals <a class="header-anchor" href="#design-goals" aria-label="Permalink to “Design Goals”">​</a></h2><p>The goal of <code>useColorComputed</code> is to <strong>centrally and uniformly handle all color and state style logic for components</strong>, providing a reactive, configurable inline style computation solution deeply integrated with the theme system. Components only need to pass a few color-related props to obtain complete visual state representation.</p><h2 id="core-features" tabindex="-1">Core Features <a class="header-anchor" href="#core-features" aria-label="Permalink to “Core Features”">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><strong>Reactive Style Output</strong></td><td>Returns <code>ComputedRef&lt;CSSProperties&gt;</code>, supporting real-time reactivity for <code>Ref</code> types like <code>isHovered</code>/<code>isActive</code></td></tr><tr><td><strong>Complete State Coverage</strong></td><td>Prioritization: <code>disabled</code> → <code>plain</code> → custom colors → base fallback; clear and conflict-free logic</td></tr><tr><td><strong>Intelligent Plain Mode Handling</strong></td><td>Distinguishes between <code>default</code> type and colored types (e.g., primary), automatically uses theme variables and handles hover/active switching with transparency</td></tr><tr><td><strong>Deep Theme Variable Support</strong></td><td>Uses <code>useColorUtils.toRGBA</code> to achieve transparency conversion for <code>var(--xxx)</code>, ensuring seamless collaboration with CSS variable systems</td></tr><tr><td><strong>Custom Color Priority</strong></td><td>When <code>colorBg</code>, <code>colorText</code>, or <code>colorBorder</code> are passed, they directly override theme logic, supporting full customization</td></tr><tr><td><strong>Uniform Disabled State</strong></td><td>Fixed as transparent background + white text/border for strong visual consistency</td></tr><tr><td><strong>Type Safe</strong></td><td><code>ColorComputedProps</code> interface clearly constrains props, supporting full TypeScript inference</td></tr></tbody></table><h2 id="design-value" tabindex="-1">Design Value <a class="header-anchor" href="#design-value" aria-label="Permalink to “Design Value”">​</a></h2><p><code>useColorComputed</code> is a critical part of visual consistency in the component library. Together with <code>useClassComputed</code> and <code>useStyleComputed</code>, it forms a complete presentation layer solution:</p><ul><li><code>useClassComputed</code> → Handles structured class names (BEM)</li><li><code>useStyleComputed</code> → Handles general inline styles like dimensions and layout</li><li><code>useColorComputed</code> → Focuses on color and states (plain, hover, active, disabled)</li></ul><p>Through this Hook:</p><ul><li>Color behavior is highly consistent across all components, eliminating repetitive complex conditionals</li><li>Deeply bound to the theme system (CSS variables), automatically adapting when themes switch</li><li>Supports custom colors and plain mode, balancing flexibility and standards</li><li>Smooth reactive state switching for a unified interactive experience</li></ul>',15)])])}const h=o(i,[["render",s]]);export{m as __pageData,h as default};
